
import { collection, getDocs, query, where, limit } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import type { Driver } from './drivers';
import { getStudents } from './students';


export type UserRole = 'admin' | 'driver' | 'parent';

export interface UserData {
    name: string;
    email: string;
    role: UserRole;
}

// The admin role is hardcoded for simplicity.
const ADMIN_EMAILS = ['admin@yellowtransit.com'];

async function getDriverData(email: string): Promise<Driver | null> {
    const driversRef = collection(db, 'drivers');
    const q = query(driversRef, where('email', '==', email), limit(1));
    const snapshot = await getDocs(q);
    if (snapshot.empty) {
        return null;
    }
    return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Driver;
}

async function getParentData(email: string): Promise<{ name: string; email: string } | null> {
    const students = await getStudents();
    const studentWithParent = students.find(student => student.parent.email === email);
    if (studentWithParent) {
        return studentWithParent.parent;
    }
    return null;
}

export const getUserRole = async (email: string): Promise<UserRole | null> => {
    if (ADMIN_EMAILS.includes(email)) {
        return 'admin';
    }
    if (await getDriverData(email)) {
        return 'driver';
    }
    if (await getParentData(email)) {
        return 'parent';
    }
    return null;
}

export const getUserData = async (email: string): Promise<UserData | null> => {
    if (ADMIN_EMAILS.includes(email)) {
        return { name: 'Admin User', email, role: 'admin' };
    }

    const driver = await getDriverData(email);
    if (driver) {
        return { name: driver.name, email, role: 'driver' };
    }

    const parent = await getParentData(email);
    if (parent) {
        return { name: parent.name, email, role: 'parent' };
    }

    return null;
}
